from dataclasses import dataclass
from decimal import Decimal

@dataclass
class Tx:
    amount: Decimal
    def __post_init__(self):
        if self.amount < 0:
            raise ValueError("amount >= 0")
print(Tx(Decimal("1")))
try:
    Tx(Decimal("-1"))
except ValueError as e:
    print("err", e)

from dataclasses import dataclass

@dataclass
class Client:
    client_id: str
    nombre: str
    @classmethod
    def from_dict(cls, d):
        if "client_id" not in d:
            raise ValueError("missing client_id")
        return cls(d["client_id"], d.get("nombre", ""))
print(Client.from_dict({"client_id": "C1", "nombre": "Ana"}))

