from dataclasses import dataclass, field
from typing import List

@dataclass
class Case:
    _tags: List[str] = field(default_factory=list)
    def add_tag(self, t: str) -> None:
        if t and t not in self._tags:
            self._tags.append(t)
    @property
    def tags(self):
        return list(self._tags)
c = Case()
c.add_tag("review")
print(c.tags)

