from typing import Protocol

class Scorer(Protocol):
    def score(self, a: str, b: str) -> float: ...

class ExactScorer:
    def score(self, a: str, b: str) -> float:
        return 1.0 if a == b else 0.0
print(ExactScorer().score("a", "a"))

class Exact:
    def score(self, a, b):
        return 1.0 if a == b else 0.0
class AlwaysHalf:
    def score(self, a, b):
        return 0.5
def run(scorer, a, b):
    return scorer.score(a, b)
print(run(Exact(), "x", "x"), run(AlwaysHalf(), "x", "y"))

from dataclasses import dataclass, asdict

@dataclass
class ClientRecord:
    client_id: str
    nombre: str
print(asdict(ClientRecord("C1", "Ana")))

class InMemoryRepo:
    def __init__(self):
        self._d = {}
    def save(self, entity):
        self._d[entity["id"]] = entity
    def get(self, id_):
        return self._d.get(id_)
r = InMemoryRepo()
r.save({"id": "C1", "n": "Ana"})
print(r.get("C1"))

