class FakeRepo:
    def __init__(self):
        self.data = {}
    def save(self, e):
        self.data[e["id"]] = e
    def get(self, i):
        return self.data[i]
r = FakeRepo()
r.save({"id": "C1"})
assert r.get("C1")["id"] == "C1"
assert "C2" not in r.data
r.save({"id": "C2"})
assert len(r.data) == 2
